<?php
$pageTitle='Lot & Serial Tracking';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('lot_serial_tracking');
$pdo=getDB();
$products=$pdo->query('SELECT id,sku,name FROM '.table('products').' ORDER BY name LIMIT 500')->fetchAll();$warehouses=$pdo->query('SELECT id,warehouse_name FROM '.table('warehouses').' ORDER BY warehouse_name')->fetchAll();$bins=$pdo->query('SELECT id,bin_code,bin_name FROM '.table('warehouse_bins').' ORDER BY bin_code')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{if(($_POST['form_type']??'')==='lot'){createInventoryLot($pdo,(int)$_POST['product_id'],(int)$_POST['warehouse_id'],0,(int)$_POST['bin_id'],max(0,(float)$_POST['quantity']),trim((string)$_POST['manufacture_date']),trim((string)$_POST['expiry_date']),trim((string)$_POST['notes']));flash('success','Lot created.');}else{createInventorySerial($pdo,(int)$_POST['product_id'],trim((string)$_POST['serial_number']),(int)$_POST['warehouse_id'],0,(int)$_POST['bin_id'],(int)$_POST['lot_id'],trim((string)$_POST['notes']));flash('success','Serial number created.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'lot-serial']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/lot-serial-tracking.php');}
$lots=$pdo->query('SELECT l.*,p.sku,p.name,w.warehouse_name,b.bin_code FROM '.table('inventory_lots').' l LEFT JOIN '.table('products').' p ON p.id=l.product_id LEFT JOIN '.table('warehouses').' w ON w.id=l.warehouse_id LEFT JOIN '.table('warehouse_bins').' b ON b.id=l.bin_id ORDER BY l.created_at DESC LIMIT 100')->fetchAll();
$serials=$pdo->query('SELECT s.*,p.sku,p.name,l.lot_number FROM '.table('inventory_serial_numbers').' s LEFT JOIN '.table('products').' p ON p.id=s.product_id LEFT JOIN '.table('inventory_lots').' l ON l.id=s.lot_id ORDER BY s.created_at DESC LIMIT 150')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Traceability</div><h2 class="h4 mb-1">Lot & Serial Tracking</h2><p class="text-secondary mb-0">Track batches, expiry, serial numbers, and product traceability.</p></div></div><div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="form_type" value="lot"><h2 class="h5 mb-3">Create Lot</h2><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?php echo (int)$w['id']; ?>"><?php echo esc($w['warehouse_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="bin_id"><option value="0">No bin</option><?php foreach($bins as $b): ?><option value="<?php echo (int)$b['id']; ?>"><?php echo esc($b['bin_code'].' · '.$b['bin_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="number" step="0.0001" name="quantity" value="1"><div class="row g-2"><div class="col-6"><input class="form-control" type="date" name="manufacture_date"></div><div class="col-6"><input class="form-control" type="date" name="expiry_date"></div></div><textarea class="form-control my-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Lot</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="form_type" value="serial"><h2 class="h5 mb-3">Add Serial</h2><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="serial_number" placeholder="Serial number"><select class="form-select mb-2" name="warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?php echo (int)$w['id']; ?>"><?php echo esc($w['warehouse_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="bin_id"><option value="0">No bin</option><?php foreach($bins as $b): ?><option value="<?php echo (int)$b['id']; ?>"><?php echo esc($b['bin_code']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="lot_id"><option value="0">No lot</option><?php foreach($lots as $l): ?><option value="<?php echo (int)$l['id']; ?>"><?php echo esc($l['lot_number']); ?></option><?php endforeach; ?></select><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Add Serial</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Lots</h2><table class="table"><thead><tr><th>Lot</th><th>Product</th><th>Warehouse/Bin</th><th>Qty</th><th>Expiry</th></tr></thead><tbody><?php foreach($lots as $l): ?><tr><td><strong><?php echo esc($l['lot_number']); ?></strong></td><td><?php echo esc($l['sku'].' · '.$l['name']); ?></td><td><?php echo esc($l['warehouse_name'].' / '.$l['bin_code']); ?></td><td><?php echo number_format((float)$l['quantity'],4); ?></td><td><?php echo esc($l['expiry_date']); ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Serial Numbers</h2><table class="table"><thead><tr><th>Serial</th><th>Product</th><th>Lot</th><th>Status</th></tr></thead><tbody><?php foreach($serials as $s): ?><tr><td><strong><?php echo esc($s['serial_number']); ?></strong></td><td><?php echo esc($s['sku'].' · '.$s['name']); ?></td><td><?php echo esc($s['lot_number']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>